	; (ymm1) m'_i = s'_i since f'_i = 0

	; -deltaU_A calculation
	; skip. For this node, A is not defined at any level (local, region, nor global).

	; -deltaU_J calculation
	; [load group 1]
	; skip. For edge, J is not defined at any level (local, region, nor global).
	; skip parameter loading for the null load group
	; [load group 2]
	; edge: 1_4_9 -> 2_4_9
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (130)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_1_4_9 (neighbor)
	vmulsd xmm0, xmm9, qword ptr [m_R + OFFSETOF_REGION_J]  ; load J_m_R (region)
	; [load group 3]
	; edge: 2_4_8 -> 2_4_9
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (220)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_2_4_8 (neighbor)
